INSERT INTO vector.ouch_chunks (chunk_id, doc_id, issue_date, title, chunk_index, chunk_chars, text_content, embedding)
VALUES ('07_2022_Ataki_phishingowe_chunk_0001', '07_2022_Ataki_phishingowe', '07/2022', 'Ataki phishingowe', 1, 1799, 'rozpoznanie swojej ofiary, tak aby stworzyć spersonalizowany atak. Zamiast rozsyłać wiadomości phishingowe do milionów osób lub podszywać się pod generyczne wiadomości wysyłane przez korporacje, mogą wysłać je do garstki osób i tak dostosować atak, aby wyglądał na wysłany przez kogoś, kogo znamy. Cyberprzestępcy szukają informacji: ● przeszukując profile w serwisie LinkedIn, informacje zamieszczane w mediach społecznościowych lub wykorzystując publicznie dostępne informacje lub znalezione w sieci TOR. ● wysyłając spreparowanie wiadomości, które wydają się pochodzić od kierownictwa, współpracowników lub sprzedawców, których znasz i z którymi pracujesz. ● dowiadując się jakie są zainteresowania użytkownika i wysyłając do niego wiadomość, podając się za kogoś, kto podziela wspólne zainteresowania. ● określając, że byłeś na konferencji lub właśnie wróciłeś z podróży, a następnie wysyłając wiadomości e-mail nawiązującej do podróży. Cyberprzestępcy aktywnie wykorzystują inne metody dotarcia do ofiary, np. wysyłając te same wiadomości za pośrednictwem SMS-ów lub dzwoniąc bezpośrednio do niej. 
Ataki phishingowe 
Biuletyn Bezpieczeństwa Komputerowego 
OUCH! Lipiec 2022

© SANS Institute 2022 www.sans.org/security-awareness
W jaki sposób wykryć te bardziej zaawansowane ataki phishingowe Przestępcy poświęcają dużo czasu na rozpoznanie swojej ofiary, dlatego wykrycie tego typu ataków może być trudne. Dobra wiadomość jest taka, że można je rozpoznać jeśli wiemy na co spojrzeć i czego szukać. Przed podjęciem jakichkolwiek działań z podejrzaną wiadomością należy zadać sobie następujące pytania: 1. Czy wiadomość wywołuje zwiększone poczucie pilności? Czy wywiera presję, aby ominąć zasady bezpieczeństwa obowiązujące w Twojej organizacji? Czy jesteś popędzany do popełnienia błędu? Im w', '[-0.024972615763545036, 0.0008477310184389353, -0.08010450750589371, -0.07075432687997818, 0.04790256544947624, -0.025073477998375893, 0.024423671886324883, -0.004987853113561869, 0.007791453506797552, 0.021744318306446075, 0.03695112466812134, 0.087849922478199, 0.10890763998031616, 0.03085908107459545, 0.06185213476419449, -0.015589808113873005, 0.04161752387881279, -0.0435042642056942, 0.007396743632853031, 0.06070363521575928, -0.002286717528477311, -0.06553799659013748, 0.0823669284582138, -0.008304260671138763, -0.06570258736610413, -0.054923877120018005, -0.03258359432220459, -0.02533569745719433, -0.13277074694633484, -0.01440441608428955, 0.021374857053160667, -0.0306917205452919, -0.050689179450273514, 0.07091917842626572, -0.04517832398414612, 0.004340941086411476, -0.008962941356003284, 0.0493791326880455, 0.03879412263631821, -0.002067304216325283, 0.004619428422302008, -0.011174503713846207, -0.010261219926178455, 0.02434149570763111, -0.04459306225180626, -0.01681113801896572, -0.01909598521888256, 0.09192317724227905, -0.06553557515144348, -0.04379655793309212, -0.02353174425661564, -0.010020679794251919, 0.029335403814911842, 0.1038660928606987, 0.01348494179546833, -0.03780798241496086, -0.04031623899936676, -0.026541749015450478, 0.011415802873671055, 0.0170223880559206, 0.05034051835536957, 0.010160003788769245, 0.001901018782518804, -0.01399398036301136, 0.018705109134316444, 0.0300694964