9, 0.02615298517048359, 0.07058422267436981, -0.06611014157533646, 0.03418901190161705, 0.01326650008559227, -0.027631446719169617, 0.039106979966163635, -0.0037034275010228157, 0.053700003772974014, -0.05717058479785919, -0.006341429427266121, -0.04146122187376022, 0.03427619859576225, 0.07359221577644348, 0.03847488388419151, -0.0365523099899292, 0.032104384154081345, 0.1105382889509201, 0.031760312616825104, 0.06060924008488655, 0.0698406770825386, 0.044755980372428894, 0.006234194152057171, -0.08395229279994965, -0.03909788280725479, -0.028677165508270264, 0.014359747059643269, 0.04137951508164406, 0.06951954215765, -0.01282273605465889, -0.003049061866477132, -0.004608699586242437, -0.07159852981567383, 0.02016236074268818, -0.019464489072561264, -0.05070435255765915, 0.043846067041158676, -0.14864586293697357, 0.006636759731918573, -0.035499751567840576, -0.06520797312259674, 0.028429199010133743, -0.016224989667534828, 0.028957029804587364, -0.07410251349210739, 0.013593833893537521, 0.09722977876663208, 0.05792820453643799, 0.03372078761458397, 0.02670329622924328, -0.035235095769166946, 0.03619193658232689, 0.049995820969343185, -0.027951965108513832, -0.025142638012766838, 0.05841982364654541, 0.016549717634916306]'::vector)
