INSERT INTO vector.ouch_chunks (chunk_id, doc_id, issue_date, title, chunk_index, chunk_chars, text_content, embedding)
VALUES ('10_2018_Jak_unikn_b_d_w_korzystaj_c_z_poczty_e-mail_chunk_0000', '10_2018_Jak_unikn_b_d_w_korzystaj_c_z_poczty_e-mail', '10/2018', 'Jak uniknąć błędów, korzystając z poczty e-mail?', 0, 1800, 'Wprowadzenie
Poczta e-mail stanowi obecnie jeden z najbardziej popularnych środków komunikacji, zarówno w życiu prywatnym, jak i 
zawodowym. Korzystając z poczty elektronicznej, warto mieć świadomość błędów, jakie możemy popełnić. Poniżej podajemy 
4 najbardziej popularne rodzaje pomyłek, a także sposoby, pomagające ich uniknąć.
Autouzupełnianie
Autouzupełnianie to popularna funkcjonalność, dostępna w większości programów pocztowych. Wystarczy, że wpiszesz 
imię osoby, do której adresowana jest wiadomość, a program pocztowy sam uzupełni pole z adresem e-mail. Dzięki 
temu, nie musisz zapamiętywać adresów wszystkich swoich znajomych, wystarczy znajomość imienia. Problem 
pojawia się, kiedy w Twojej książce adresowej znajdzie się wiele kontaktów do osób o tym samym imieniu. Łatwo 
wtedy o popełnienie błędu i wysłanie wiadomości do niewłaściwej osoby. Wyobraź sobie sytuację, w której chcesz 
zaadresować ważną wiadomość służbową do “Joanny Nowak”, księgowej z Twojej firmy. W wyniku pomyłki, korzystając 
z opcji autouzupełniania, wybierasz z listy “Joannę Nowacką”, wychowawczynię Twojej córki. W wyniku błędu, poufna 
wiadomość służbowa trafia do niewłaściwego adresata. Chcąc chronić się przed tego typu błędami, zawsze sprawdź 
dwa razy imię, nazwisko i adres odbiorcy.
Odpowiedz wszystkim
Tworząc wiadomość e-mail, posiadasz możliwość przekazania jej kopii adresatom z pola „CC:”. W wolnym tłumaczeniu 
„CC:” oznacza kalkę (ang. „Carbon Copy”). Daje ona możliwość przesłania e-maila „do wiadomości” innych osób (w 
polskojęzycznych aplikacjach możesz spotkać się z polem o nazwie „DW:”). Otrzymując wiadomość z listą adresatów w 
polu “CC:”, możesz zdecydować, czy chcesz odpisać wyłącznie nadawcy, czy skorzystać z opcji „odpowiedz wszystkim” 
i wysłać kopię wiadomości także do pozos', '[-0.039136603474617004, -0.07034695893526077, -0.03162793070077896, -0.026240693405270576, -0.030757615342736244, -0.02321748435497284, 0.020379019901156425, 0.003493059892207384, 0.06721453368663788, 0.0035989582538604736, -0.010948131792247295, 0.08341092616319656, 0.05590897053480148, 0.00856584869325161, 0.0031608431600034237, 0.010716673918068409, -0.006756855174899101, -0.01811929978430271, 0.03323284536600113, 0.04599066823720932, -0.0203144121915102, -0.0048346794210374355, 0.046761248260736465, 0.016813242807984352, -0.0282619409263134, -0.049540162086486816, -0.009827944450080395, -0.008668183349072933, -0.10992453247308731, -0.10171432793140411, 0.09176348149776459, 0.01041827630251646, 0.121860072016716, 0.0676603689789772, -0.06899119168519974, 0.05313945934176445, -0.0101908715441823, 0.04425370693206787, 0.005955653730779886, -0.07537338882684708, -0.007968774065375328, -0.11616093665361404, 0.02331450954079628, -0.03514808788895607, -0.019697781652212143, -0.00018398462270852178, -0.012388726696372032, 0.029224373400211334, 0.0024221381172537804, 0.05901574343442917, 0.029314933344721794, 0.03152400627732277, -0.045301809906959534, 0.06669726967811584, 0.010972138494253159, -0.038621459156274796, 0.02618289738893509, 0.041051484644412994, -0.06462009251117706, 0.033005837351083755, 0.04138263314962387, -0.004175751004368067, -0.007706495001912117, 0.06576184183359146, -0.009648521430790424, 0.04269493371248245, 0.026336342096328735, -0.0014606162440031767, -0.040759485214948654, -0.04643634334206581, -0.10967785865068436, -0.027361968532204628, -0.08175303041934967, 0.05470423400402069, 0.04259103164076805, 0.07740847021341324, -0.09496847540140152, 0.005886404309421778, 0.012361174449324608, 0.06618044525384903, 0.03417794406414032, 0.03950072452425957, -0.0675874873995781, 0.014221333898603916, -0.05419234186410904, 0.02449510619044304, 0.06590084731578827, -0.07100974023342133, -0.01664036326110363, -0.0