INSERT INTO vector.ouch_chunks (chunk_id, doc_id, issue_date, title, chunk_index, chunk_chars, text_content, embedding)
VALUES ('05_2018_RODO_GDPR_chunk_0002', '05_2018_RODO_GDPR', '05/2018', 'RODO (GDPR)', 2, 1800, 'ikowania należytej staranności w celu ochrony danych osobowych podczas przekazywania ich do podmiotów 
trzecich, w szczególności poza terytorium Unii Europejskiej. W przypadku “wycieku” danych osobowych, organizacja powinna 
zaraportować o tym w przeciągu 72 godzin od uświadomienia sobie incydentu. Nieprzestrzeganie przepisów wymaganych 
przez RODO/GDPR może skutkować grzywną sięgającą 4% rocznych obrotów przedsiębiorstwa, co czyni je jedną z najbardziej 
kosztownych finansowo regulacji na świecie.
Polski przekład
CERT Polska jest zespołem działającym w strukturach NASK powołanym do reagowania na zdarzenia naruszające 
bezpieczeństwo w polskiej sieci Internet. Należy do organizacji FIRST, w ramach której współpracuje z podobnymi zespołami 
na całym świecie.
WWW: http://www.cert.pl
